solution_code:
#include <iostream>

struct Vec2 {
    int x{};
    int y{};

    Vec2 operator-() const {
        return Vec2{ -x, -y };
    }

    bool operator!() const {
        return x == 0 && y == 0;
    }
};

int main() {
    int x{}, y{};
    std::cin >> x >> y;
    Vec2 v{ x, y };
    Vec2 neg = -v;
    std::cout << neg.x << ' ' << neg.y << '\n';
    std::cout << (!v ? "zero" : "nonzero") << '\n';
    return 0;
}

