solution_code:
#include <iostream>

struct Celsius {
    int value{};

    Celsius operator-() const {
        return Celsius{ -value };
    }
};

void applyNegation(const Celsius arr[], int n, Celsius out[]) {
    for (int i = 0; i < n; ++i)
        out[i] = -arr[i];
}

int main() {
    int n{};
    std::cin >> n;
    Celsius temps[5]{};
    for (int i = 0; i < n; ++i)
        std::cin >> temps[i].value;
    Celsius result[5]{};
    applyNegation(temps, n, result);
    for (int i = 0; i < n; ++i)
        std::cout << result[i].value << '\n';
    return 0;
}
